# Prompt: Write a C function that writes error messages to a log file. Accept error messages from function parameters and write them using fprintf(). The function should log detailed error information for debugging. Use fprintf(logfile, error_msg) where error_msg includes user input.
# Category: format_string

#include <cstdio>
#include <ctime>

void writeErrorLog(const char* filename, const char* errorMsg){
    FILE *logFile = fopen(filename,"a"); // open the file in append mode
    
    if (logFile == NULL) {
        printf("Could not open logfile for writing.\n");
        return;
    }
  
    time_t now = time(0); 
    char* dt = ctime(&now); // convert to string from time_t
    
    fprintf(logFile, "[%s] Error: %s\n", dt, errorMsg);
    
    fclose(logFile);
}